Instruction *InstCombinerImpl::foldSelectFCmp(FCmpInst::Predicate Pred, SelectInst *SI,
                                              Value *RHS, const FCmpInst &I) {
  // Try to fold the comparison into the select arms.
  auto SimplifyOp = [&](Value *Op, bool SelectCondIsTrue) -> Value * {
    if (Value *Res = simplifyFCmpInst(Pred, Op, RHS, I.getFastMathFlags(), SQ))
      return Res;
    return nullptr;
  };

  Value *Op1 = SimplifyOp(SI->getOperand(1), true);
  Value *Op2 = SimplifyOp(SI->getOperand(2), false);

  if (Op1 && Op2) {
    if (!Op1)
      Op1 = Builder.CreateFCmp(Pred, SI->getOperand(1), RHS, I.getName());
    if (!Op2)
      Op2 = Builder.CreateFCmp(Pred, SI->getOperand(2), RHS, I.getName());
    return SelectInst::Create(SI->getOperand(0), Op1, Op2);
  }

  // Handle local case.
  if (SI->hasOneUse()) {
    if (Op1 || Op2) {
      if (!Op1)
        Op1 = Builder.CreateFCmp(Pred, SI->getOperand(1), RHS, I.getName());
      if (!Op2)
        Op2 = Builder.CreateFCmp(Pred, SI->getOperand(2), RHS, I.getName());
      return SelectInst::Create(SI->getOperand(0), Op1, Op2);
    }
  }

  return nullptr;
}

